Here's a C++ program that implements a dictionary using a binary search tree (BST). The program allows users to insert words and their definitions, search for words, delete words, and display the entire dictionary.

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

using namespace std;

// Node structure for BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST operations
class Dictionary {
public:
    Dictionary() : root(nullptr) {}

    ~Dictionary() {
        deleteTree(root);
    }

    void insert(string word, string definition) {
        root = insertNode(root, word, definition);
    }

    Node* insertNode(Node* root, string word, string definition) {
        if (root == nullptr) {
            return new Node(word, definition);
        }

        if (word < root->word) {
            root->left = insertNode(root->left, word, definition);
        } else {
            root->right = insertNode(root->right, word, definition);
        }

        return root;
    }

    void deleteWord(string word) {
        root = deleteNode(root, word);
    }

    Node* deleteNode(Node* root, string word) {
        if (root == nullptr) return root;

        if (word < root->word) {
            root->left = deleteNode(root->left, word);
        } else if (word > root->word) {
            root->right = deleteNode(root->right, word);
        } else {
            // Node found, delete it
            if (root->left == nullptr) {
                Node* temp = root;
                root = root->right;
                delete temp;
            } else if (root->right == nullptr) {
                Node* temp = root;
                root = root->left;
                delete temp;
            } else {
                // Find the inorder successor
                Node* temp = findInorderSuccessor(root->right);
                root->word = temp->word;
                root->definition = temp->definition;

                // Delete the inorder successor
                root->right = deleteNode(root->right, temp->word);
            }
        }

        return root;
    }

    Node* findInorderSuccessor(Node* node) {
        Node* successor = node->right;
        while (successor->left != nullptr) {
            successor = successor->left;
        }
        return successor;
    }

    void search(string word) {
        Node* node = root;
        while (node != nullptr) {
            if (node->word == word) {
                cout << "Found: " << word << " => " << node->definition << endl;
                return;
            } else if (word < node->word) {
                node = node->left;
            } else {
                node = node->right;
            }
        }

        cout << "Not found." << endl;
    }

    void display() {
        displayTree(root, 0);
    }

    void displayTree(Node* node, int level) {
        if (node != nullptr) {
            displayTree(node->right, level + 1);
            cout << string(level * 2, ' ') << node->word << " => " << node->definition << endl;
            displayTree(node->left, level + 1);
        }
    }

    void deleteTree(Node* node) {
        if (node != nullptr) {
            deleteTree(node->left);
            deleteTree(node->right);
            delete node;
        }
    }
};

int main() {
    Dictionary dict;
    string word, definition;

    while (true) {
        cout << "Enter a word and its definition (or 'exit' to quit): ";
        cin >> word >> definition;

        if (word == "exit") {
            break;
        }

        dict.insert(word, definition);
    }

    cout << "\nDictionary Contents:\n";
    dict.display();

    cout << "\nEnter a word to look up: ";
    cin >> word;

    dict.search(word);

    cout << "\nEnter a word to delete: ";
    cin >> word;

    dict.deleteWord(word);

    cout << "\nDictionary Contents after deletion:\n";
    dict.display();

    return 0;
}
```

### Features:
- **Insertion**: Words and definitions are inserted into the BST.
- **Search**: Users can look up a word and see its definition.
- **Deletion**: Users can delete a word and its definition.
- **Display**: The entire dictionary is printed in a structured format.

### Usage:
1. Run the program.
2. Enter words and their definitions.
3. Use commands like `exit`, `search`, `delete`, and `display` to interact with the dictionary.
4. The program outputs clean and well-formatted results.

This implementation provides a robust and efficient way to manage a dictionary using a binary search tree.

