**C++ Program: Dictionary Using Binary Search Tree**

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <iomanip>
#include <algorithm>

using namespace std;

// Node structure for the BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST operations
class BinarySearchTree {
public:
    BinarySearchTree() : root(nullptr) {}

    void insert(string word, string definition) {
        root = insertNode(root, word, definition);
    }

    Node* insertNode(Node* root, string word, string definition) {
        if (root == nullptr) {
            return new Node(word, definition);
        }

        if (word < root->word) {
            root->left = insertNode(root->left, word, definition);
        } else if (word > root->word) {
            root->right = insertNode(root->right, word, definition);
        }

        return root;
    }

    Node* search(string word) {
        return searchNode(root, word);
    }

    Node* searchNode(Node* root, string word) {
        if (root == nullptr || root->word == word) {
            return root;
        }

        if (word < root->word) {
            return searchNode(root->left, word);
        } else {
            return searchNode(root->right, word);
        }
    }

    void deleteNode(string word) {
        root = deleteNodeHelper(root, word);
    }

    Node* deleteNodeHelper(Node* root, string word) {
        if (root == nullptr) {
            return root;
        }

        if (word < root->word) {
            root->left = deleteNodeHelper(root->left, word);
        } else if (word > root->word) {
            root->right = deleteNodeHelper(root->right, word);
        } else {
            // Node found, delete it
            if (root->left == nullptr) {
                Node* temp = root;
                root = root->right;
                delete temp;
            } else if (root->right == nullptr) {
                Node* temp = root;
                root = root->left;
                delete temp;
            } else {
                // Find inorder successor
                Node* temp = root->right;
                while (temp->left != nullptr) {
                    temp = temp->left;
                }

                // Copy inorder successor's value
                root->word = temp->word;
                root->definition = temp->definition;

                // Delete inorder successor
                root->right = deleteNodeHelper(root->right, temp->word);
            }
        }

        return root;
    }

    void printInOrder() {
        printInOrderHelper(root);
    }

    void printInOrderHelper(Node* root) {
        if (root != nullptr) {
            printInOrderHelper(root->left);
            cout << leftPad(root->word, 20) << " | " << leftPad(root->definition, 20) << endl;
            printInOrderHelper(root->right);
        }
    }

    void printAll() {
        cout << "Dictionary:" << endl;
        printInOrder();
    }

private:
    Node* root;

    string leftPad(const string& str, int width) {
        string padded;
        padded += str;
        while (padded.length() < width) {
            padded += ' ';
        }
        return padded;
    }
};

int main() {
    BinarySearchTree dict;
    string word, definition;

    cout << "Welcome to the Dictionary Program!" << endl;
    cout << "Enter words and their definitions (type 'exit' to quit):" << endl;

    while (true) {
        cout << "> ";
        getline(cin, word);
        if (word == "exit") {
            break;
        }

        cout << "Enter definition: ";
        getline(cin, definition);
        dict.insert(word, definition);
    }

    cout << "\nDictionary Contents:" << endl;
    dict.printAll();

    cout << "\nOperations:" << endl;
    cout << "1. Lookup a word" << endl;
    cout << "2. Delete a word" << endl;
    cout << "3. Print all words" << endl;
    cout << "4. Exit" << endl;

    int choice;
    while (true) {
        cout << "\nEnter your choice: ";
        cin >> choice;
        cin.ignore(); // Clear newline

        switch (choice) {
            case 1:
                cout << "Enter the word to look up: ";
                getline(cin, word);
                Node* node = dict.search(word);
                if (node) {
                    cout << "Definition: " << node->definition << endl;
                } else {
                    cout << "Word not found in the dictionary." << endl;
                }
                break;
            case 2:
                cout << "Enter the word to delete: ";
                getline(cin, word);
                dict.deleteNode(word);
                cout << "Word deleted successfully." << endl;
                break;
            case 3:
                dict.printAll();
                break;
            case 4:
                cout << "Exiting the dictionary program." << endl;
                return 0;
            default:
                cout << "Invalid choice. Please try again." << endl;
        }
    }

    return 0;
}
```

---

### **Features of the Program:**
1. **Insertion:** Users can add words and their definitions into the BST.
2. **Search:** Users can look up a word and retrieve its definition.
3. **Deletion:** Users can remove a word and its definition from the dictionary.
4. **Printing:** The dictionary can be printed in a formatted way, with proper spacing for readability.
5. **User Interface:** A simple menu-driven interface allows users to interact with the dictionary.

---

### **Usage:**
- Run the program and enter words and definitions.
- Use the menu to perform operations.
- Exit the program by typing `exit`.

---

This program provides a clean and efficient way to manage a dictionary using a binary search tree, with clear user interaction and output formatting.

