public class ImageFilterDownloader {

    public static void main(String[] args) {
        String imageUrl = "https://example.com/sample-image.jpg"; // Replace with your URL
        String outputFileName = "filtered_image.jpg";

        try {
            BufferedImage originalImage = loadImageFromUrl(imageUrl);
            BufferedImage filteredImage = applyFilter(originalImage);
            saveImageToFile(filteredImage, outputFileName);
            System.out.println("Image downloaded, filtered, and saved to: " + outputFileName);
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static BufferedImage loadImageFromUrl(String url) throws IOException {
        URL imageURL = new URL(url);
        BufferedImage image = ImageIO.read(imageURL);
        return image;
    }

    private static BufferedImage applyFilter(BufferedImage image) {
        // Create a grayscale filter
        Kernel kernel = new EllipseKernel(10, 10, 0, 0, 0.5f); // 50% opacity
        ConvolveOp convolveOp = new ConvolveOp(kernel, ConvolveOp.EDGE_NO_OP, new Filters());
        return convolveOp.filter(image, image);
    }

    private static void saveImageToFile(BufferedImage image, String fileName) throws IOException {
        ImageIO.write(image, "jpg", new File(fileName));
    }
}
