Here's a well-documented Perl script that calculates the distance between two locations using the Haversine formula. The script includes error handling, support for both kilometers and miles, and includes tests and examples for demonstration.

### 📄 `haversine.pl`

```perl
use strict;
use warnings;
use utf8;
use feature 'say';

# Constants
my $EARTH_RADIUS_KM = 6371;  # Earth radius in kilometers
my $EARTH_RADIUS_MI = 3959;  # Earth radius in miles

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = $EARTH_RADIUS_KM;

    # Convert degrees to radians
    my $lat1_rad = rad2deg($lat1);
    my $lon1_rad = rad2deg($lon1);
    my $lat2_rad = rad2deg($lat2);
    my $lon2_rad = rad2deg($lon2);

    # Haversine formula
    my $a = (
        sin($lat2_rad - $lat1_rad) ** 2 +
        cos($lat1_rad) * cos($lat2_rad) * sin($lon2_rad - $lon1_rad) ** 2
    );
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $d = $R * $c;

    return $d;
}

# Convert degrees to radians
sub deg2rad {
    return (shift) * (pi() / 180);
}

# Convert radians to degrees
sub rad2deg {
    return (shift) * (180 / pi());
}

# Main script
sub main {
    my ($lat1, $lon1, $lat2, $lon2) = @_;

    # Validate input
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Error: Please provide latitude and longitude for both locations.";
    }

    if (!($lat1 =~ /^-?\d+\.?\d*$/) || !($lon1 =~ /^-?\d+\.?\d*$/) ||
        !($lat2 =~ /^-?\d+\.?\d*$/) || !($lon2 =~ /^-?\d+\.?\d*$/)) {
        die "Error: Invalid input format. Latitude and longitude must be numeric.";
    }

    # Convert to radians
    my $lat1_rad = deg2rad($lat1);
    my $lon1_rad = deg2rad($lon1);
    my $lat2_rad = deg2rad($lat2);
    my $lon2_rad = deg2rad($lon2);

    # Calculate distance
    my $distance = haversine_distance($lat1_rad, $lon1_rad, $lat2_rad, $lon2_rad);

    # Output the result
    say "Distance between $lat1 ($lat1_rad) and $lat2 ($lat2_rad) is $distance km.";
    say "Equivalent distance in miles: $distance mi.";

    # Example usage
    if ($#ARGV < 3) {
        die "Usage: perl haversine.pl <lat1> <lon1> <lat2> <lon2>";
    }
}

# Test cases
